from __future__ import annotations
import enum
from dataclasses import dataclass, field
from typing import Optional

class DocumentQualityStatus(enum.Enum):
    PASS       = "pass"
    WARN       = "warn"
    STALE      = "stale"        # freshness failure → queue re-ingest
    INCOMPLETE = "incomplete"   # completeness failure → block retrieval
    CRITICAL   = "critical"     # both failures → block + page oncall

@dataclass
class DocumentQualityReport:
    doc_id: str
    freshness: FreshnessResult
    field_completeness: FieldCompletenessResult
    chunk_completeness: ChunkCompletenessResult
    status: DocumentQualityStatus
    all_violations: list[str] = field(default_factory=list)

    def blocks_retrieval(self) -> bool:
        return self.status in {
            DocumentQualityStatus.STALE,
            DocumentQualityStatus.INCOMPLETE,
            DocumentQualityStatus.CRITICAL,
        }

    def requires_oncall(self) -> bool:
        return self.status == DocumentQualityStatus.CRITICAL

def build_document_quality_report(
    freshness: FreshnessResult,
    field_result: FieldCompletenessResult,
    chunk_result: ChunkCompletenessResult,
) -> DocumentQualityReport:
    violations = (
        freshness.violations
        + field_result.missing_required
        + chunk_result.violations
    )

    freshness_fail = freshness.status == FreshnessStatus.STALE
    completeness_fail = not field_result.passes or not chunk_result.passes

    if freshness_fail and completeness_fail:
        status = DocumentQualityStatus.CRITICAL
    elif freshness_fail:
        status = DocumentQualityStatus.STALE
    elif completeness_fail:
        status = DocumentQualityStatus.INCOMPLETE
    elif freshness.status == FreshnessStatus.WARN:
        status = DocumentQualityStatus.WARN
    elif freshness.status == FreshnessStatus.MISSING:
        status = DocumentQualityStatus.INCOMPLETE
    else:
        status = DocumentQualityStatus.PASS

    return DocumentQualityReport(
        doc_id=freshness.doc_id,
        freshness=freshness,
        field_completeness=field_result,
        chunk_completeness=chunk_result,
        status=status,
        all_violations=violations,
    )

from __future__ import annotations
from typing import Any

class FreshnessAwareRetriever:
    """Wraps a vector store retriever and drops chunks whose document
    is currently in STALE, INCOMPLETE, or CRITICAL status."""

    def __init__(
        self,
        base_retriever,
        quality_store: dict[str, str],   # doc_id → status string
        *,
        block_on_warn: bool = False,
    ):
        self._retriever = base_retriever
        self._quality = quality_store
        self._block_warn = block_on_warn

    def retrieve(self, query: str, *, top_k: int = 5) -> list[dict[str, Any]]:
        candidates = self._retriever.retrieve(query, top_k=top_k * 2)

        passed, blocked = [], []
        for chunk in candidates:
            doc_id = chunk.get("metadata", {}).get("doc_id")
            status = self._quality.get(doc_id, "pass")
            blocks = status in {"stale", "incomplete", "critical"}
            if status == "warn" and self._block_warn:
                blocks = True
            if blocks:
                blocked.append((doc_id, status))
            else:
                passed.append(chunk)

        if blocked:
            import logging
            logging.getLogger(__name__).info(
                "retrieve: dropped %d chunks (docs: %s)",
                len(blocked),
                [(d, s) for d, s in blocked[:5]],
            )

        return passed[:top_k]
